    # count primes until you reach the nth one
    pass

questions.solution:
def nth_prime(n):
    def prime(k):
        if k < 2:
            return False
        i = 2
        while i * i <= k:
            if k % i == 0:
                return False
            i += 1
        return True
    count = 0
    k = 1
    while count < n:
        k += 1
        if prime(k):
            count += 1
    return k

